// <T> captures whatever type is passed at the call site
function identity<T>(value: T): T {
  return value;
}

const num = identity(42);      // T is inferred as number
const str = identity('hello'); // T is inferred as string

// extends constrains T to only types that have .length
function longest<T extends { length: number }>(a: T, b: T): T {
  return a.length >= b.length ? a : b;
}

longest('cat', 'elephant'); // strings have length
longest([1, 2], [1, 2, 3]); // arrays have length too

// Multiple type parameters are separated by commas
function pair<T, U>(first: T, second: U): [T, U] {
  return [first, second];
}

const result = pair('Alice', 30);
// result is typed as [string, number]

// Box<T> wraps any value while preserving its type
interface Box<T> {
  value: T;
  get(): T;
  set(value: T): void;
}

const stringBox: Box<string> = {
  value: 'hello',
  get() { return this.value; },
  set(v) { this.value = v; }
};

// Stack<T> works the same way for any element type
class Stack<T> {
  private items: T[] = [];

  push(item: T): void {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }

  peek(): T | undefined {
    return this.items[this.items.length - 1];
  }
}

// Recursively makes all properties readonly at every nesting level
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object
    ? DeepReadonly<T[K]>   // recurse into nested objects
    : T[K];                 // leave primitives as-is
};

interface Config {
  name: string;
  nested: { value: number };
}

type Frozen = DeepReadonly<Config>;
// Frozen: { readonly name: string; readonly nested: { readonly value: number } }
